#include <bits/stdc++.h>
using namespace std;
int a[16];
int main(){
    for(int i=1;i<=15;i++){
        int p,q;
        scanf("%d-%d", &p, &q);
        if(i<9){
            if(p>q)a[i]=i*2-1;
            else a[i]=i*2;
        }else if(i>8){
            if(p>q)a[i]=a[(i-8)*2-1];
            else a[i]=a[(i-8)*2];
        }
    }
    cout<<char('A'+a[15]-1);
    return 0;
}
